form:Form.form:Scripts:
		function FILTER()
{
	np = new NomadProxy("", ut);
	nSQL = np.SQLService();
	var PARAM = "<PARAM c_sujeto=\"" +Ctrl("c_sujeto").GetXValue() + "\" d_sujeto=\""+Ctrl("d_sujeto").GetXValue() + "\" oi_clasif_suj=\""+ Ctrl("oi_clasif_suj").GetXValue() + "\" />";
	var result = nSQL.GetOBJ(Ctrl("main").getResource("CantidadSujetos"), PARAM); 

	if(result.cantidad > 1000)
	{
		alert("La búsqueda devuelve más de 1000 registros, por favor afine la búsqueda.");
		return false;
	}
	else
		Ctrl("main").DoEvent("FILTER");

}
